412	  polling_url: z.url(),
413	  cost: z.number().nullish(),
414	  input_mp: z.number().nullish(),
415	  output_mp: z.number().nullish(),
416	});
417	
418	const bflStatus = z.union([
419	  z.literal('Pending'),
420	  z.literal('Ready'),
421	  z.literal('Error'),
422	  z.literal('Failed'),
423	  z.literal('Request Moderated'),
424	]);
