import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { FetchFunction, InferSchema, Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

// ---------------------------------------------------------------------------
// Model ID type
// ---------------------------------------------------------------------------

export type PixelArtImageModelId =
  | 'pixelart-v1'
  | 'pixelart-v2'
  | 'pixelart-retro'
  | (string & {});

// ---------------------------------------------------------------------------
// Provider-specific options schema
// ---------------------------------------------------------------------------

export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * The artistic style to apply to the generated pixel art image.
       * - `"pixel"`: Classic pixel art style
       * - `"retro"`: Retro game-inspired style
       * - `"8bit"`: 8-bit video game aesthetic
       */
      style: z.enum(['pixel', 'retro', '8bit']).optional(),

      /**
       * The pixel density (pixels per unit) of the generated image.
       * Higher values produce finer detail. Typical range: 1–64.
       */
      pixelDensity: z.number().positive().optional(),
    }),
  ),
);

export type PixelArtImageSettings = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

// ---------------------------------------------------------------------------
// Internal config interface
// ---------------------------------------------------------------------------

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

// ---------------------------------------------------------------------------
// Image model class
// ---------------------------------------------------------------------------

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    files,
    mask,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    // Warn about unsupported standard features
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspect ratio. Use the `size` parameter instead.',
      });
    }

    if (seed != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'seed',
        details: 'PixelArt does not support seed-based generation.',
      });
    }

    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'image',
        details: 'PixelArt does not support image-to-image generation.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details: 'PixelArt does not support inpainting with a mask.',
      });
    }

    // Parse provider-specific options
    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
    const combinedHeaders = combineHeaders(
      await resolve(this.config.headers),
      headers,
    );

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combinedHeaders,
      body: {
        model: this.modelId,
        prompt,
        n,
        size,
        style: pixelArtOptions?.style,
        pixel_density: pixelArtOptions?.pixelDensity,
      },
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          images: response.data.map(() => ({})),
          ...(response.created != null ? { created: response.created } : {}),
        },
      },
    };
  }
}

// ---------------------------------------------------------------------------
// Response schema
// ---------------------------------------------------------------------------

const pixelArtImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      created: z.number().nullish(),
      data: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

// ---------------------------------------------------------------------------
// Error handling
// ---------------------------------------------------------------------------

const pixelArtErrorSchema = z.object({
  error: z
    .object({
      message: z.string().optional(),
      code: z.string().optional(),
    })
    .optional(),
  message: z.string().optional(),
});

export const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: error => {
    const parsed = pixelArtErrorSchema.safeParse(error);
    if (!parsed.success) return 'Unknown PixelArt error';
    const { error: inner, message } = parsed.data;
    return inner?.message ?? message ?? 'Unknown PixelArt error';
  },
});

import { ImageModelV3, NoSuchModelError, ProviderV3 } from '@ai-sdk/provider';
import type { FetchFunction } from '@ai-sdk/provider-utils';
import {
  loadApiKey,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import type { PixelArtImageModelId } from './pixelart-image-model';
import { VERSION } from './version';

// ---------------------------------------------------------------------------
// Provider settings
// ---------------------------------------------------------------------------

export interface PixelArtProviderSettings {
  /**
   * PixelArt API key. Defaults to the value of the `PIXELART_API_KEY`
   * environment variable.
   */
  apiKey?: string;

  /**
   * Base URL for the PixelArt API. Defaults to `https://api.pixelart.ai/v1`.
   */
  baseURL?: string;

  /**
   * Custom headers to include in every request.
   */
  headers?: Record<string, string>;

  /**
   * Custom fetch implementation. You can use it as a middleware to intercept
   * requests, or to provide a custom fetch implementation for e.g. testing.
   */
  fetch?: FetchFunction;
}

// ---------------------------------------------------------------------------
// Provider interface
// ---------------------------------------------------------------------------

export interface PixelArtProvider extends ProviderV3 {
  /**
   * Creates a PixelArt image generation model.
   */
  image(modelId: PixelArtImageModelId): ImageModelV3;

  /**
   * Creates a PixelArt image generation model.
   */
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;

  /**
   * @deprecated PixelArt does not support text embeddings.
   */
  textEmbeddingModel(modelId: string): never;
}

// ---------------------------------------------------------------------------
// Factory function
// ---------------------------------------------------------------------------

const defaultBaseURL = 'https://api.pixelart.ai/v1';

export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL =
    withoutTrailingSlash(options.baseURL) ?? defaultBaseURL;

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const embeddingModel = (modelId: string): never => {
    throw new NoSuchModelError({
      modelId,
      modelType: 'embeddingModel',
    });
  };

  return {
    specificationVersion: 'v3',

    image: createImageModel,
    imageModel: createImageModel,

    languageModel: (modelId: string) => {
      throw new NoSuchModelError({
        modelId,
        modelType: 'languageModel',
      });
    },

    embeddingModel,
    textEmbeddingModel: embeddingModel,
  };
}

// ---------------------------------------------------------------------------
// Default provider instance
// ---------------------------------------------------------------------------

/**
 * Default PixelArt provider instance.
 */
export const pixelArt = createPixelArt();

